import React, { useState, useEffect } from "react";

import { useNavigate } from "react-router-dom";

import { Layout, Menu, Row, Grid } from "antd";
import {
  DashboardOutlined,
  WhatsAppOutlined,
  FileTextOutlined,
  TeamOutlined,
  BarChartOutlined,
  CalendarOutlined,
  
  MenuUnfoldOutlined,
  MenuFoldOutlined,
 
} from "@ant-design/icons";

import { Link } from "react-router-dom";
import { MdLogout } from "react-icons/md";

const { Header, Sider, Content, Footer } = Layout;
const { useBreakpoint } = Grid;

const TaskAdminPanelLayout = ({ children }) => {
  const [collapsed, setCollapsed] = useState(false);
  const [openKeys, setOpenKeys] = useState([]);
  const screens = useBreakpoint();
  const [, setIsMobile] = useState(false);
  const navigate = useNavigate();
  const entryPoint = localStorage.getItem("entryPoint") || "direct";
  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth <= 768);
    };
    handleResize();
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  useEffect(() => {
    if (screens.xs) {
      setCollapsed(true); // Always collapse on small screens
    } else if (screens.md) {
      setCollapsed(false); // Expand on larger screens
    }
  }, [screens]);
 const sidebarItems = [
   {
     key: "dashboard",
     label: "Dashboard Overview",
     icon: <DashboardOutlined />,
     dropdownItems: [
       {
         key: "dashboard-overview",
         label: "Overview",
       
         link: "/taskmanagement/overview",
       },
     ],
   },

   {
     key: "assignedTasks",
     label: "Assign WhatsApp Tasks",
     icon: <WhatsAppOutlined />,
     dropdownItems: [
       {
         key: "assigned-tasks-list",
         label: "Assigned Tasks",
      
         link: "/taskmanagement/tasks/assigned",
       },
     ],
   },

   {
     key: "teamAttendance",
     label: "Attendance Overview",
     icon: <TeamOutlined />,
     dropdownItems: [
       {
         key: "attendance-overview",
         label: "Attendance",
       
         link: "/taskmanagement/attendance",
       },
     ],
   },

   {
     key: "leaveManagement",
     label: "Leave Administration",
     icon: <CalendarOutlined />,
     dropdownItems: [
       {
         key: "leave-management",
         label: "Leave Management",
       
         link: "/taskmanagement/leave-management",
       },
     ],
   },

   {
     key: "employeeWorkLogs",
     label: "Employee Work Logs",
     icon: <FileTextOutlined />,
     dropdownItems: [
       {
         key: "todayWorkLog",
         label: "Today's POD/EOD",
       
         link: "/taskmanagement/work-logs/today",
       },
       {
         key: "workLogHistory",
         label: "All Employees Reports",
        
         link: "/taskmanagement/work-logs/history",
       },
     ],
   },

   {
     key: "dailyReports",
     label: "Daily Plans Reports",
     icon: <BarChartOutlined />,
     dropdownItems: [
       {
         key: "dailyWorkPlan",
         label: "Daily Work Plan",
       
         link: "/taskmanagement/reports/daily-plan",
       },
       {
         key: "dailyWorkSummary",
         label: "Daily Work Summary",
       
         link: "/taskmanagement/reports/daily-summary",
       },
     ],
   },
 ];


  const toggleCollapse = () => {
    setCollapsed((prev) => !prev);
  };
  const handleOpenChange = (keys) =>
    setOpenKeys(keys.length ? [keys.pop()] : []);

  const handleSignOut = () => {
    const currentPath = window.location.pathname + window.location.search;
    localStorage.clear(); // Clear all local storage items
    sessionStorage.clear(); // Clear all session storage items
    localStorage.setItem("redirectAfterLogin_task", currentPath);
    window.location.href = "/admin/taskmanagementlogin"; // Redirect to login
  };

  const date = new Date();
  const fullYear = date.getFullYear();

  return (
    <Layout style={{ minHeight: "100vh" }}>
      <Sider
        collapsed={collapsed}
        onCollapse={setCollapsed}
        breakpoint="md"
        width={screens.xs ? 240 : 240}
        collapsedWidth={screens.xs ? 0 : 80}
        style={{
          backgroundColor: "#1A202C", // Sidebar background color
          zIndex: 1000,
          // left: collapsed ? (isMobile ? "-200px" : "-80px") : 0,
          left: 0,
          top: 0,
          transition: "left 0.3s ease-in-out", // Smoother transition
          position: "fixed",
          height: "100vh",
          overflowY: "auto",
        }}
      >
        <div className="demo-logo-vertical" style={{ padding: "10px 0" }}>
          <Row justify="center" align="middle">
            <div
              className=" text-center font-bold my-0"
              style={{ fontSize: 24 }}
            >
              <Link
                to="/taskmanagement/overview"
                style={{
                  fontSize: "20px",
                  color: "#fff",
                  textAlign: "center",
                  textDecoration: "none", // Add this if you want to remove underline
                }}
              >
                <span>
                  <span style={{ color: "#008cba", fontWeight: 700 }}>
                    {collapsed ? "T" : "Task "}
                  </span>
                  {!collapsed && (
                    <span style={{ color: "#1ab394", fontWeight: 700 }}>
                      Management
                    </span>
                  )}
                </span>
              </Link>
            </div>
          </Row>
        </div>
        <div
          style={{ textAlign: "center", marginTop: "0px" }}
          className="bg-gray-800 text-white my-5 h-6"
        >
          <Link
            to="/taskmanagement/overview"
            style={{ textDecoration: "none" }}
          >
            <strong
              className="my-6"
              style={{ fontSize: "14px", fontWeight: 700 }}
            >
              <span style={{ color: "#008cba" }}>
                {collapsed ? "T" : "Task "}
              </span>
              {!collapsed && <span style={{ color: "#595959" }}>Admin</span>}
            </strong>
          </Link>
        </div>
        <Menu
          theme="" // or "" if you prefer default dark mode styles
          mode="inline"
          openKeys={openKeys}
          onOpenChange={handleOpenChange}
          style={{
            color: "#A7B1C2",
          }}
        >
          {sidebarItems.map((item) =>
            item.dropdownItems ? (
              <Menu.SubMenu
                key={item.key}
                icon={item.icon}
                title={
                  <span className={` ${collapsed ? "hidden" : "inline"}`}>
                    {item.label}
                  </span>
                }
                className="text-white hover:bg-black hover:text-black"
              >
                {item.dropdownItems.map((dropdownItem) => (
                  <Menu.Item
                    key={dropdownItem.key}
                    className="bg-gray-800 text-white hover:bg-black hover:text-white" // Unified background and hover behavior
                  >
                    <Link
                      to={dropdownItem.link}
                      className="flex items-center text-white hover:text-black no-underline"
                    >
                      {/* Ensure icon is rendered correctly */}
                      <span className="mr-1 text-white hover:text-black">
                        {dropdownItem.icon}{" "}
                        {/* icon should be a valid JSX element */}
                      </span>
                      <span className="hover:text-black">
                        {dropdownItem.label}
                      </span>
                    </Link>
                  </Menu.Item>
                ))}
              </Menu.SubMenu>
            ) : (
              <Menu.Item
                key={item.key}
                className="text-white" // Remove background on hover
              >
                <Link
                  to={item.link}
                  className="flex items-center text-white hover:text-black no-underline"
                >
                  <span className=" hover:text-black">{item.icon}</span>
                  <span
                    className={`ml-2 ${collapsed ? "hidden" : "inline"} hover:text-black`}
                  >
                    {item.label}
                  </span>
                </Link>
              </Menu.Item>
            ),
          )}
        </Menu>
      </Sider>

      <Layout>
        <Header
          style={{
            padding: screens.xs ? "0 12px" : "0 18px",
            background: "#fff",
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            boxShadow: "0 1px 4px rgba(0, 0, 0, 0.1)",
            width: screens.xs
              ? "100%"
              : `calc(100% - ${collapsed ? "80px" : "240px"})`,
            marginLeft: screens.xs ? "0px" : collapsed ? "80px" : "240px",
            position: "fixed",
            top: 0,
            zIndex: 9,
            height: 64, // Ensure it's positioned correctly
          }}
        >
          <button
            onClick={toggleCollapse}
            style={{
              background: "none",
              border: "none",
              cursor: "pointer",
              fontSize: "18px",
              color: "#1AB394",
            }}
          >
            {collapsed ? <MenuUnfoldOutlined /> : <MenuFoldOutlined />}
          </button>

          <div
            onClick={handleSignOut}
            style={{ display: "flex", alignItems: "center", cursor: "pointer" }}
          >
            <MdLogout
              style={{ marginRight: "8px", color: "#999C9E", fontSize: "14px" }}
            />
            <span style={{ color: "#999C9E", fontSize: "14px" }}>Log out</span>
          </div>
        </Header>
        <Content
          style={{
            margin: screens.xs
              ? "80px 16px 16px"
              : `80px 16px 16px ${collapsed ? "80px" : "240px"}`,
            padding: screens.xs ? 12 : 24,
            background: "#fff",
            width: screens.xs
              ? "100%"
              : `calc(100% - ${collapsed ? "80px" : "240px"})`,
            marginLeft: screens.xs ? "0px" : collapsed ? "80px" : "240px",
            position: "relative", // Ensure it's positioned correctly
          }}
        >
          {children}
        </Content>
        <Footer
          style={{
            textAlign: "center",
            background: "#fff",
            width: screens.xs
              ? "100%"
              : `calc(100% - ${collapsed ? "80px" : "240px"})`,
            marginLeft: screens.xs ? "0px" : collapsed ? "80px" : "240px",
            position: "relative", // Ensure it's positioned correctly
            bottom: 0,
          }}
        >
          ASKOXY.AI Admin ©{fullYear} Created by ASKOXY.AI Company
        </Footer>
      </Layout>
      {/* Custom scrollbar styling */}
      <style>{`
        /* Customize scrollbar for the menu */
        .ant-menu::-webkit-scrollbar {
          width: 5px;
        }

        .ant-menu::-webkit-scrollbar-track {
          background: #1a202c;
        }

        .ant-menu::-webkit-scrollbar-thumb {
          background-color: #4a5568;
          border-radius: 10px;
        }

        /* For Firefox */
        .ant-menu {
          scrollbar-width: thin;
          scrollbar-color: #4a5568 #1a202c;
        }

        /* Custom scrollbar for the entire Sider */
        .ant-layout-sider::-webkit-scrollbar {
          width: 5px;
        }

        .ant-layout-sider::-webkit-scrollbar-track {
          background: #1a202c;
        }

        .ant-layout-sider::-webkit-scrollbar-thumb {
          background-color: #4a5568;
          border-radius: 10px;
        }

        /* For Firefox */
        .ant-layout-sider {
          scrollbar-width: thin;
          scrollbar-color: #4a5568 #1a202c;
        }

        /* Menu hover + active colors to keep text visible */
        .ant-menu-dark,
        .ant-menu-dark .ant-menu-sub,
        .ant-layout-sider .ant-menu {
          background: #1a202c;
          color: #e2e8f0;
        }

        .ant-layout-sider .ant-menu-item,
        .ant-layout-sider .ant-menu-submenu-title {
          color: #e2e8f0;
        }

        .ant-layout-sider .ant-menu-item a,
        .ant-layout-sider .ant-menu-submenu-title span {
          color: #e2e8f0;
        }

        .ant-layout-sider .ant-menu-item:hover,
        .ant-layout-sider .ant-menu-item-active,
        .ant-layout-sider .ant-menu-submenu-title:hover,
        .ant-layout-sider .ant-menu-submenu-open,
        .ant-layout-sider .ant-menu-item-selected {
          background-color: #2d3748 !important;
          color: #ffffff !important;
        }

        .ant-layout-sider .ant-menu-item:hover a,
        .ant-layout-sider .ant-menu-item-active a,
        .ant-layout-sider .ant-menu-item-selected a,
        .ant-layout-sider .ant-menu-submenu-title:hover span {
          color: #ffffff !important;
        }
      `}</style>
    </Layout>
  );
};

export default TaskAdminPanelLayout;
